// Some portions generated by Co-Pilot
import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { filterByCurrentDate } from "../filterByDate";

const FIXED_NOW = new Date("2025-06-15T12:00:00Z");

describe("filterByCurrentDate", () => {
  beforeEach(() => {
    vi.useFakeTimers();
    vi.setSystemTime(FIXED_NOW);
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("returns all items when no dates are set", () => {
    const items: Array<{
      label: string;
      startDate?: string;
      endDate?: string;
    }> = [{ label: "a" }, { label: "b" }];
    expect(filterByCurrentDate(items)).toEqual(items);
  });

  it("includes an item whose date range spans now", () => {
    const items = [{ startDate: "2025-01-01", endDate: "2025-12-31" }];
    expect(filterByCurrentDate(items)).toHaveLength(1);
  });

  it("excludes an item whose endDate is in the past", () => {
    const items = [{ startDate: "2025-01-01", endDate: "2025-03-01" }];
    expect(filterByCurrentDate(items)).toHaveLength(0);
  });

  it("excludes an item whose startDate is in the future", () => {
    const items = [{ startDate: "2025-09-01", endDate: "2025-12-31" }];
    expect(filterByCurrentDate(items)).toHaveLength(0);
  });

  it("includes an item with no startDate but a future endDate", () => {
    const items = [{ endDate: "2025-12-31" }];
    expect(filterByCurrentDate(items)).toHaveLength(1);
  });

  it("includes an item with a past startDate and no endDate", () => {
    const items = [{ startDate: "2025-01-01" }];
    expect(filterByCurrentDate(items)).toHaveLength(1);
  });

  it("excludes an item with no startDate and a past endDate", () => {
    const items = [{ endDate: "2025-03-01" }];
    expect(filterByCurrentDate(items)).toHaveLength(0);
  });

  it("excludes an item with a future startDate and no endDate", () => {
    const items = [{ startDate: "2025-09-01" }];
    expect(filterByCurrentDate(items)).toHaveLength(0);
  });

  it("returns an empty array when given an empty array", () => {
    expect(filterByCurrentDate([])).toEqual([]);
  });

  it("returns only the valid items from a mixed array", () => {
    const items: Array<{ id: number; startDate?: string; endDate?: string }> = [
      { id: 1, startDate: "2025-01-01", endDate: "2025-12-31" }, // valid
      { id: 2, startDate: "2025-09-01", endDate: "2025-12-31" }, // future start
      { id: 3, endDate: "2025-03-01" }, // expired
      { id: 4 }, // no dates, always valid
    ];
    const result = filterByCurrentDate(items);
    expect(result.map((i) => i.id)).toEqual([1, 4]);
  });

  it("preserves extra fields on matching items", () => {
    const items = [
      { startDate: "2025-01-01", endDate: "2025-12-31", title: "Hello" },
    ];
    expect(filterByCurrentDate(items)[0].title).toBe("Hello");
  });
});
